import React from "react";
import { Link } from "react-router-dom";
import "../styles/AllNews.css";

const allNews = [
  {
    id: 1,
    title: "Post 1 Title",
    description: "This is a short description for the first news post.",
    image: "/images/1.jpg",
  },
  {
    id: 2,
    title: "Post 2 Title",
    description: "This is a short description for the second news post.",
    image: "/images/news2.jpg",
  },
  {
    id: 3,
    title: "Post 3 Title",
    description: "This is a short description for the third news post.",
    image: "/images/news3.jpg",
  },
  // You can add more news posts here
];

const AllNews = () => {
  return (
    <div className="all-news-section">
      <h2 className="section-title">All News</h2>
      <div className="all-news-posts">
        {allNews.map((post) => (
          <div key={post.id} className="news-card">
            <img src={post.image} alt={post.title} className="news-image" />
            <h3>{post.title}</h3>
            <p>{post.description}</p>
            <Link to={`/news/${post.id}`} className="read-more">Read More</Link>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AllNews;
